function normalizeText(value) {
  return String(value ?? '')
    .replace(/\u0000/g, '')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function isPdfFile(meta, key) {
  const mime = String(meta?.mimeType ?? '').toLowerCase();
  const fileName = String(meta?.fileName ?? key ?? '').toLowerCase();
  const extRaw = String(meta?.fileExtension ?? '').toLowerCase();
  const ext = extRaw.startsWith('.') ? extRaw.slice(1) : extRaw;

  return mime.includes('pdf') || ext === 'pdf' || fileName.endsWith('.pdf');
}

function looksTextLike(meta, key) {
  const mime = String(meta?.mimeType ?? '').toLowerCase();
  const extRaw = String(meta?.fileExtension ?? '').toLowerCase();
  const ext = extRaw.startsWith('.') ? extRaw.slice(1) : extRaw;

  const textExt = new Set([
    'txt','md','markdown','json','yaml','yml','xml','csv','tsv','ini','cfg','conf','env',
    'js','mjs','cjs','ts','tsx','jsx','py','java','kt','go','rs','rb','php','sql','html','htm','log','sh','ps1'
  ]);

  if (mime.startsWith('text/')) return true;
  if (mime.includes('json') || mime.includes('xml') || mime.includes('yaml') || mime.includes('csv')) return true;
  if (textExt.has(ext)) return true;

  const keyLower = String(key ?? '').toLowerCase();
  return keyLower.endsWith('.txt') || keyLower.endsWith('.md') || keyLower.endsWith('.json') || keyLower.endsWith('.yaml') || keyLower.endsWith('.yml');
}

function decodePdfLiteral(inner) {
  let out = '';
  for (let i = 0; i < inner.length; i += 1) {
    const ch = inner[i];
    if (ch !== '\\') {
      out += ch;
      continue;
    }

    const next = inner[i + 1];
    if (next === undefined) break;

    if (next === '\\' || next === '(' || next === ')') {
      out += next;
      i += 1;
      continue;
    }

    if (next === 'n') { out += '\n'; i += 1; continue; }
    if (next === 'r') { out += '\r'; i += 1; continue; }
    if (next === 't') { out += '\t'; i += 1; continue; }
    if (next === 'b') { out += '\b'; i += 1; continue; }
    if (next === 'f') { out += '\f'; i += 1; continue; }

    if (/[0-7]/.test(next)) {
      let oct = next;
      let consumed = 1;
      for (let j = 2; j <= 3; j += 1) {
        const c = inner[i + j];
        if (c !== undefined && /[0-7]/.test(c)) {
          oct += c;
          consumed += 1;
        } else {
          break;
        }
      }
      out += String.fromCharCode(parseInt(oct, 8));
      i += consumed;
      continue;
    }

    out += next;
    i += 1;
  }
  return out;
}

function extractPdfText(buffer) {
  const src = buffer.toString('latin1');
  const lines = [];

  const simpleMatches = src.match(/\((?:\\.|[^\\)])*\)\s*Tj/g) ?? [];
  for (const token of simpleMatches) {
    const m = token.match(/^\(((?:\\.|[^\\)])*)\)\s*Tj$/);
    if (!m) continue;
    const text = normalizeText(decodePdfLiteral(m[1]));
    if (text) lines.push(text);
  }

  const arrayMatches = src.match(/\[(?:.|\n|\r)*?\]\s*TJ/g) ?? [];
  for (const token of arrayMatches) {
    const chunks = token.match(/\((?:\\.|[^\\)])*\)/g) ?? [];
    const pieces = chunks
      .map((c) => c.slice(1, -1))
      .map((c) => normalizeText(decodePdfLiteral(c)))
      .filter(Boolean);
    if (pieces.length) lines.push(pieces.join(' '));
  }

  const joined = normalizeText(lines.join('\n'));
  return joined;
}

async function readBinaryBuffer(index, key, meta) {
  if (typeof this?.helpers?.getBinaryDataBuffer === 'function') {
    try {
      const buf = await this.helpers.getBinaryDataBuffer(index, key);
      if (buf && buf.length) return buf;
    } catch {}
  }

  const raw = String(meta?.data ?? '');
  if (raw && raw !== 'filesystem-v2') {
    try {
      return Buffer.from(raw, 'base64');
    } catch {}
  }

  return Buffer.alloc(0);
}

const entries = Object.entries(binary);
if (!entries.length) {
  throw new Error('No files were extracted from requirements ZIP.');
}

const extracted = [];
const skipped = [];

for (const [key, meta] of entries) {
  const fileName = String(meta?.fileName ?? key);
  if (!fileName || fileName.endsWith('/')) continue;

  const buffer = await readBinaryBuffer.call(this, 0, key, meta);
  if (!buffer.length) {
    skipped.push({ fileName, reason: 'empty_binary' });
    continue;
  }

  let text = '';

  if (isPdfFile(meta, key)) {
    text = extractPdfText(buffer);
    if (!text) {
      skipped.push({ fileName, reason: 'pdf_text_not_found' });
      continue;
    }
  } else if (looksTextLike(meta, key)) {
    text = normalizeText(buffer.toString('utf8'));
    if (!text) {
      skipped.push({ fileName, reason: 'decoded_text_empty' });
      continue;
    }
  } else {
    skipped.push({ fileName, reason: 'unsupported_non_text_file' });
    continue;
  }

  extracted.push({ fileName, text });
}

if (!extracted.length) {
  throw new Error(
    'No readable text files found in ZIP for requirements generation. Skipped: ' + JSON.stringify(skipped)
  );
}

const corpus = extracted
  .map((f) => [
